@csrf @if($receta)@method('PUT')@endif
<div class="row g-3"><div class="col-md-6"><label class="form-label">Nombre</label><input class="form-control" name="nombre" value="{{ old('nombre',$receta?->nombre) }}" required></div><div class="col-md-3"><label class="form-label">Tiempo de preparacion</label><input type="number" min="1" class="form-control" name="tiempo_preparacion" value="{{ old('tiempo_preparacion',$receta?->tiempo_preparacion) }}" required></div><div class="col-md-3"><label class="form-label">Precio</label><input type="number" min="0" step="0.01" class="form-control" name="precio" value="{{ old('precio',$receta?->precio) }}" required></div><div class="col-12"><label class="form-label">Descripcion</label><textarea class="form-control" name="descripcion">{{ old('descripcion',$receta?->descripcion) }}</textarea></div><div class="col-12"><label class="form-label">Indicaciones</label><textarea class="form-control" name="indicaciones" required>{{ old('indicaciones',$receta?->indicaciones) }}</textarea></div><div class="col-md-6"><label class="form-label">Imagen</label><input type="file" class="form-control" name="imagen" accept="image/*"></div></div>
<section class="border-top mt-4 pt-4"><h4>Presentaciones utilizadas</h4><div class="row g-2 align-items-end mb-3"><div class="col-md-7"><label class="form-label">Presentacion</label><select id="presentacion-temp" class="form-select">@foreach($presentaciones as $p)<option value="{{ $p->id }}">{{ $p->insumo->nombre }} - {{ $p->nombre }} ({{ $p->unidadStock()?->abreviatura }})</option>@endforeach</select></div><div class="col-md-3"><label class="form-label">Cantidad por porcion</label><input id="cantidad-temp" type="number" min="0.0001" step="0.0001" class="form-control"></div><div class="col-md-2"><button type="button" id="agregar-presentacion" class="btn btn-secondary"><i class="lni lni-plus"></i> Agregar</button></div></div><div class="table-responsive"><table class="table"><thead><tr><th>Presentacion</th><th>Cantidad</th><th></th></tr></thead><tbody id="presentaciones-receta">@if($receta)@foreach($receta->insumos as $insumo)@php($p=$presentaciones->firstWhere('id',$insumo->pivot->presentacion_id))@if($p)<tr><td>{{ $p->insumo->nombre }} - {{ $p->nombre }} ({{ $p->unidadStock()?->abreviatura }})</td><td>{{ $insumo->pivot->cantidad }}</td><td><button type="button" class="btn btn-danger btn-sm quitar"><i class="lni lni-trash-can"></i></button><input type="hidden" name="insumos[{{ $loop->index }}][presentacion_id]" value="{{ $p->id }}"><input type="hidden" name="insumos[{{ $loop->index }}][cantidad]" value="{{ $insumo->pivot->cantidad }}"></td></tr>@endif @endforeach @endif</tbody></table></div></section>
<div class="mt-4"><button class="btn btn-primary">Guardar receta</button> <a class="btn btn-secondary" href="{{ route('recetas.index') }}">Cancelar</a></div>
<script>document.addEventListener('DOMContentLoaded',()=>{let i=document.querySelectorAll('#presentaciones-receta tr').length;const tbody=document.getElementById('presentaciones-receta');tbody.addEventListener('click',e=>{const b=e.target.closest('.quitar');if(b)b.closest('tr').remove()});document.getElementById('agregar-presentacion').addEventListener('click',()=>{const s=document.getElementById('presentacion-temp'),c=document.getElementById('cantidad-temp');if(!c.value||Number(c.value)<=0)return;const tr=document.createElement('tr');tr.innerHTML=`<td>${s.selectedOptions[0].text}</td><td>${c.value}</td><td><button type="button" class="btn btn-danger btn-sm quitar"><i class="lni lni-trash-can"></i></button><input type="hidden" name="insumos[${i}][presentacion_id]" value="${s.value}"><input type="hidden" name="insumos[${i}][cantidad]" value="${c.value}"></td>`;tbody.appendChild(tr);i++;c.value=''})});</script>
